Modified regret-based insertion prioritizing orders by time window tightness, using penalized marginal cost scoring that balances distance increase, load violation risk, and deadline slack, with forced insertion fallback preserving feasibility.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		bestAssignIdx := -1
		bestScore := math.MaxFloat64
		var savedBestState Assign
		savedStates := make([]Assign, dispatch.AssignsLen)
		feasibleFound := false

		timeWindowPenaltyBase := 1000.0
		if oris[shipIdx].TimeEnd > oris[shipIdx].TimeStart {
			tightness := float64(oris[shipIdx].Load) / float64(oris[shipIdx].TimeEnd-oris[shipIdx].TimeStart+1)
			timeWindowPenaltyBase += tightness * 500.0
		}

		for i := 0; i < dispatch.AssignsLen; i++ {
			savedStates[i] = dispatch.Assigns[i]
			ok := dispatch.Assigns[i].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if ok {
				dispatch.Assigns[i].GenRoute()
				delta := dispatch.Assigns[i].Cost - savedStates[i].Cost

				loadRisk := 0.0
				if dispatch.Assigns[i].StationCurrent.Load > 80 {
					loadRisk = float64(dispatch.Assigns[i].StationCurrent.Load) * 0.5
				}

				deadlineSlack := 0.0
				currentTime := int(savedStates[i].Cost) // approximate from previous cost
				if dess[shipIdx].TimeEnd > currentTime {
					deadlineSlack = float64(dess[shipIdx].TimeEnd-currentTime)
				}

				penalizedScore := delta + timeWindowPenaltyBase*0.01 + loadRisk*10.0 - deadlineSlack*0.05
				if penalizedScore < bestScore {
					bestScore = penalizedScore
					bestAssignIdx = i
					savedBestState = savedStates[i]
					feasibleFound = true
				}
				dispatch.Assigns[i] = savedStates[i]
				dispatch.Assigns[i].GenRoute()
			}
		}

		if feasibleFound && bestAssignIdx >= 0 {
			dispatch.Assigns[bestAssignIdx] = savedBestState
			dispatch.Assigns[bestAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
		} else {
			inserted := false
			if dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				ok := dispatch.Assigns[idx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
				if ok {
					dispatch.Assigns[idx].GenRoute()
					dispatch.AssignsLen++
					inserted = true
				}
			}
			if !inserted {
				for i := 0; i < dispatch.AssignsLen; i++ {
					ok := dispatch.Assigns[i].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
					if ok {
						dispatch.Assigns[i].GenRoute()
						break
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

